-- Nave Data
select FT.ID_FILE_TYPE, FT.TYPE_NAME, FTI.*
from TFM_FILE_TYPE_ISSUER_FIELD FTI
inner join  TFM_FILE_TYPE FT on FTI.ID_FILE_TYPE = FT.ID_FILE_TYPE
where type_name like 'DATA_DUMP_RPT%'

select * from TFM_FILE_TYPE where type_name like 'DATA_DUMP_RPT%'
select * from TFM_FILE_TYPE where type_name like 'DATA_DUMP_RPT_PENALTY_INTEREST'
select * from TFM_FILE_TYPE_ISSUER_FIELD WHERE ID_FILE_TYPE = 223
select ID_FILE_TYPE, 999 as ID_ISSUER, FIELD, IS_VISIBLE, LENGTH from TFM_FILE_TYPE_ISSUER_FIELD WHERE ID_FILE_TYPE = 192 order by ID_FILE_ISSUER_FIELD


